```nginx
limit_req_zone $binary_remote_addr zone=api:10m rate=200r/m;

server {
  listen 443 ssl;
  server_name api.ma-boutique.com;

  ssl_certificate /etc/ssl/certs/ma-boutique.crt;
  ssl_certificate_key /etc/ssl/private/ma-boutique.key;

  location / {
    limit_req zone=api burst=10 nodelay;
    proxy_pass http://localhost:3000;
    proxy_set_header Host $host;
    proxy_set_header X-Real-IP $remote_addr;
  }
}
```

On utilise <strong>Redis</strong> comme stockage centralisé avec <code>@nestjs/throttler-storage-redis</code>. Configuration :
```typescript
ThrottlerModule.forRoot({
  storage: new ThrottlerStorageRedisService(redisClient),
  ttl: 60,
  limit: 100,
});
```
Ainsi, toutes les instances partagent le même compteur pour chaque IP.

```typescript
app.enableCors({
  origin: ['https://www.ma-boutique.com', 'https://admin.ma-boutique.com', 'http://localhost:3000'],
  credentials: true,
  methods: ['GET', 'POST', 'PUT', 'PATCH', 'DELETE', 'OPTIONS'],
  allowedHeaders: ['Content-Type', 'Authorization'],
});
```

```yaml
# docker-compose.yml
version: '3.8'
services:
  api:
    build: ./api
    environment:
      - REDIS_HOST=redis
  nginx:
    image: nginx:alpine
    ports:
      - "80:80"
      - "443:443"
    volumes:
      - ./nginx.conf:/etc/nginx/nginx.conf
    depends_on:
      - api
  redis:
    image: redis:alpine
```
```nginx
# nginx.conf
upstream backend {
  server api:3000;
}
server {
  listen 80;
  location / {
    proxy_pass http://backend;
    proxy_set_header X-Real-IP $remote_addr;
  }
}
```
